            id: widget.id || '',
            type: widget.type || '',
            runtime: widget.runtime || '',
            entry: widget.entry || '',
            app_id: widget.app_id || '',
            title: widget.title || '',
            builtin: isBuiltinType,
            autoSize: widgetShouldAutoSize(widget)
