        const tabContent = host.querySelector('[data-tab-content]');
        const qcTabs = host.querySelector('[data-qc-tabs]');
        const filterButtons = Array.from(host.querySelectorAll('[data-qc-filter]'));
        let activeWS = null;
        let activeTerm = null;
